    {%- set step_index = row.get("step_index", -1) -%}
    {%- if row.get("message").startswith('Completed task')  -%}
         {%- set _ = statusMap.update({ step_index: "success"}) -%}
    {%- elif row.get("message").startswith('Task failed')  -%}
         {%- set _ = statusMap.update({ step_index: "failed"}) -%}
    {%- elif row.get("message").startswith('Task skipped')  -%}
         {%- set _ = statusMap2.update({ step_index: "skipped"}) -%}
    {%- elif row.get("message").startswith('Starting task')  -%}
         {%- set _ = statusMap2.update({ step_index: "in_progress"}) -%}
    {%- endif -%}

    {%- if step_index not in logs -%}
        {%- set _ = logs.update({ step_index: [] }) -%}
    {%- endif -%}

    {%- if step_index not in log_data -%}
        {%- set _ = log_data.update({ step_index: [] }) -%}
    {%- endif -%}

    {% set _ = logs[step_index].append(row["severity"]+": "+row["message"].replace("\n","\\n")) %}
    {% set _ = log_data[step_index].append(row) %}

{%- endfor -%}

{% set wf = rt.get("workflow") %}

{% set tasks = wf.get("tasks", []) %}

[
    {% for task in tasks %}
        {% set taskStr = "\\n".join(logs.get(loop.index0, [])) %}
        {
            {% set index = loop.index0 %}
            "index": {{index}},
            "name1": "{{task.get("description", task.get("type"))}}",
            "name": "{{task.get("label", task.get("type"))}}",
            "logs": "{{taskStr}}",
            "status": "{{statusMap.get(index, statusMap2.get(index, "not_executed"))}}",
            "data": [
