                    {
                        "timestamp": "{{row.timestamp}}",
                        "description": "{{row.description}}",
                        "task_type": "{{row.taskType}}",
                        "severity": "{{row.severity}}",
                        "message": "{{row.message.replace("\n","\\n")}}"
                    } {{ ", " if not loop.last else "" }}
                {% endfor %}
            ]
        } {{ ", " if not loop.last else "" }}
    {% endfor %}
]

