{%- set query = "workflow_name = '" ~ context.workflow_name ~ "' and jobId = '" + job_id + "'" -%}

{%- set ns = namespace(eval_output="No Evaluation Status", agent_output="No Output Yet", last_updated="") -%}

{%- set data = engine.query_stream_data("agent_output_stream", cfxql_query=query, sorting=[{"timestamp": "desc"}], limit=10) -%}

{%- set cfxql_query_agent_license = "conversationId = '" + job_id + "' and final_response = 'true' GET message" -%}

