    {%- set ns.last_updated = data[0]["timestamp"] -%}
{%- endif -%}

{%- for row in data -%}
    {%- set raw_eval = row.get("evaluation_output_0", "") -%}

    {#-- Clean and attempt to parse the JSON --#}
    {%- set cleaned_eval = raw_eval.strip("`").lstrip("json").strip() -%}
    {%- set json_start = cleaned_eval.find('{') -%}

