            {%- if parsed.get("agent_run") -%}
                {%- set ns.eval_output = parsed.get("agent_run") -%}
            {%- endif -%}
        {%- endif -%}
    {%- endif -%}

    {%- if row.get("agent_output_0", "") and ns.agent_output == "No Output Yet" -%}
        {%- set ns.agent_output = row.get("agent_output_0").strip("`").lstrip("html") -%}
    {%- endif -%}
{%- endfor -%}

{#-- Override with license expiry if found --#}
{%- if message | trim | lower == "ai agentic features are not available due to license expiry. please contact support to renew your license." -%}
    {%- set ns.agent_output = message -%}
{%- endif -%}

{#-- Color the status --#}
{% if ns.eval_output in ["Success", "OK"] %}
    {%- set ns.eval_output = "<font style='color: #22dd22;'>" ~ ns.eval_output ~ "</font>" -%}
{%- elif ns.eval_output == "Failure" -%}
    {%- set ns.eval_output = "<font style='color: #ff2511;'>" ~ ns.eval_output ~ "</font>" -%}
{%- endif -%}

<h3>{{agent_name}}</h3>
<h3>Last Updated: {{ns.last_updated}}</h3>
<h3>Output:</h3>
<hr/>
<strong>Final Output:</strong> {{ns.agent_output | safe}}

</div>

{% endraw %}

